#include <iostream>

struct Node {
  int data;
  int height;
  Node* left;
  Node* right;
};

struct AVL {
  Node* top = nullptr;

int height(Node* root) {
    if (root == nullptr)
      return 0;
    return root->height;
  }

  Node* newNode(int value) {
    Node* root = new Node();
    root->data = value;
    root->left = nullptr;
    root->right = nullptr;
    root->height = 1;
    return(root);
  }

  Node* RightRotation(Node* y) {
    Node* x = y->left;
    Node* T2 = x->right;
    x->right = y;
    y->left = T2;
    y->height = std::max(height(y->left), height(y->right)) + 1;
    x->height = std::max(height(x->left), height(x->right)) + 1;
    return x;
  }

  Node* LeftRotation(Node* x) {
    Node* y = x->right;
    Node* T2 = y->left;
    y->left = x;
    x->right = T2;
    x->height = std::max(height(x->left), height(x->right)) + 1;
    y->height = std::max(height(y->left), height(y->right)) + 1;
    return y;
  }

  int Balance(Node* N) {
    if (N == nullptr)
        return 0;
    return height(N->right) - height(N->left);
  }

  Node* BalanceTree(Node* root) {
  if (root == nullptr) return root;

  root->height = 1 + std::max(height(root->left), height(root->right));

  int balance = Balance(root);

  if (balance < -1 && Balance(root->left) <= 0) {
    return RightRotation(root);
  }

  if (balance < -1 && Balance(root->left) > 0) {
    root->left = LeftRotation(root->left);
    return RightRotation(root);
  }

  if (balance > 1 && Balance(root->right) >= 0) {
    return LeftRotation(root);
  }
  if (balance > 1 && Balance(root->right) < 0) {
    root->right = RightRotation(root->right);
    return LeftRotation(root);
  }

  return root;
}


  Node* Insert(Node* root, int key) { 
  if (root == nullptr) {
        Node* node = new Node;
        node->data = key;
        node->height = 1;
        node->left = nullptr;
        node->right = nullptr;
        return node;
    }

  if (key < root->data) {
    root->left = Insert(root->left, key);
  } else if (key > root->data) {
    root->right = Insert(root->right, key);
  } else {
    return root;
  }

  root->height = std::max(height(root->left), height(root->right)) + 1;

  return BalanceTree(root);
}

Node* minValueNode(Node* node) {
    Node* current = node;
    while (current && current->left != nullptr)
        current = current->left;
    return current;
}

Node* Delete(Node* root, int key) {
  if (root == nullptr) return root;

  if (key < root->data) {
    root->left = Delete(root->left, key);
  } else if (key > root->data) {
    root->right = Delete(root->right, key);
  } else {
    if ((root->left == nullptr) || (root->right == nullptr)) {
      Node* temp = root->left ? root->left : root->right;

      if (temp == nullptr) {
        temp = root;
        root = nullptr;
      } else {
        root = temp;
      }
      delete temp;
    } else {
      Node* temp = minValueNode(root->right);
      root->data = temp->data;

      root->right = Delete(root->right, temp->data);
    }
  }

  if (root == nullptr) return root;

  root->height = 1 + std::max(height(root->left), height(root->right));

  int balance = Balance(root);

  if (balance < -1 && Balance(root->left) <= 0) {
    return RightRotation(root);
  }

  if (balance < -1 && Balance(root->left) > 0) {
    root->left = LeftRotation(root->left);
    return RightRotation(root);
  }

  if (balance > 1 && Balance(root->right) >= 0) {
    return LeftRotation(root);
  }

  if (balance > 1 && Balance(root->right) < 0) {
    root->right = RightRotation(root->right);
    return LeftRotation(root);
  }

  return root;
}

  bool Exists(Node* root, int key) {
    if (root == nullptr) return false;

    if (root->data == key) {
      return true;
    }
    else if (root->data > key) {
      return Exists(root->left, key);
    }
    else {
      return Exists(root->right, key);
    }
  }
};

int main() {
  std::ios_base::sync_with_stdio(false);
  std::cin.tie(0);
  std::cout.tie(0);
  char cmd;
  AVL tree;
  int n;
  std::cin >> n;
  for (int i = 0; i < n; ++i) {
    std::cin >> cmd;
    if (cmd == 'A') {
      int x;
      std::cin >> x;
      tree.top = tree.Insert(tree.top, x);
      std::cout << (tree.top == nullptr? 0 : tree.Balance(tree.top));
      if (i < n - 1) {
        std::cout << '\n';
      }
    } else if (cmd == 'D') {
      int x;
      std::cin >> x;
      tree.top = tree.Delete(tree.top, x);
      std::cout << (tree.top == nullptr? 0 : tree.Balance(tree.top));
      if (i < n - 1) {
        std::cout << '\n';
      }
    } else if (cmd == 'C') {
      int x;
      std::cin >> x;
      tree.Exists(tree.top, x) ? std::cout << 'Y' : std::cout << 'N';
      if (i < n - 1) {
        std::cout << '\n';
      }
    }
  }
}


после выполнения ротаций баланс не всегда корректен(либо высота) исправь

Основная проблема, которая может приводить к некорректным результатам после выполнения ротаций, может быть связана с некорректным обновлением высоты узлов. После удаления узла и его замены на узел с минимальным значением из правого поддерева, нужно обеспечить, чтобы обновление высот и баланс происходило не только для удаляемого узла, но и для всех его предков. 

Давайте попробуем исправить эту проблему:

1. Исправим фактическую высоту узлов. После каждого добавления или удаления должно происходить обновление высоты относительно детей узла.
2. Убедимся, что баланс вычисляется правильно в каждой ситуации.

В вашем коде нет нужды переделывать функции ротаций или повторно вводить балансировку после рекурсивного вызова функции `Delete`, так как операция ротации уже учитывает высоту и баланс дерева.

Исправим ваш код таким образом:

```cpp
...

Node* BalanceTree(Node* node) {
    if (node == nullptr) return node;

    node->height = 1 + std::max(height(node->left), height(node->right));
    int balance = Balance(node);

    // Left Left Case
    if (balance < -1 && Balance(node->left) <= 0)
        return RightRotation(node);

    // Left Right Case
    if (balance < -1 && Balance(node->left) > 0) {
        node->left = LeftRotation(node->left);
        return RightRotation(node);
    }

    // Right Right Case
    if (balance > 1 && Balance(node->right) >= 0)
        return LeftRotation(node);

    // Right Left Case
    if (balance > 1 && Balance(node->right) < 0) {
        node->right = RightRotation(node->right);
        return LeftRotation(node);
    }

    return node;
}

...

Node* Delete(Node* root, int key) {
  if (root == nullptr) return root;

  // Perform the normal BST delete
  if (key < root->data) {
    root->left = Delete(root->left, key);
  } else if (key > root->data) {
    root->right = Delete(root->right, key);
  } else {
    // Node with only one child or no child
    if ((root->left == nullptr) || (root->right == nullptr)) {
      Node* temp = root->left ? root->left : root->right;

      // No child case
      if (temp == nullptr) {
        temp = root;
        root = nullptr;
      } else {
        *root = *temp; // Copy the contents of the non-empty child
      }
      delete temp;
    } else {
      // Node with two children: Get the inorder successor (smallest in the right subtree)
      Node* temp = minValueNode(root->right);
      root->data = temp->data;
      root->right = Delete(root->right, temp->data);
    }
  }

  // If the tree had only one node then return
  if (root == nullptr)
    return root;

  // STEP 2: UPDATE HEIGHT OF THE CURRENT NODE
  root->height = 1 + std::max(height(root->left), height(root->right));

  // STEP 3: GET THE BALANCE FACTOR OF THIS NODE (to check whether this node became unbalanced)
  return BalanceTree(root); // This line will balance the tree if required
}
```

Заметьте, что вместо присваивания `root = temp;` в случае удаления узла с одним ребенком, мы делаем `*root = *temp;`, чтобы не потерять связи с потомками и заменяем содержимое — таким образом, избегая необходимости дополнительной перебалансировки предков удаленного узла. Это также поможет сохранить корректные связи в структуре дерева.

После удаления узла мы также вызываем функцию `BalanceTree` для корректной балансировки родительских узлов.

