  // Right Right Case или Right Left Case
  if (node->balance > 1) {
    // Если правое поддерево правого ребенка как минимум сбалансировано или правонаклонено
    if (node->right != nullptr && node->right->balance >= 0) {
      return LeftRotation(node);
    } else { // Right Left Case - требуется двойная ротация
      node->right = RightRotation(node->right);
      return LeftRotation(node);
    }
  }

  return node;
}
