проверь правильность функции insert

Сначала давайте рассмотрим, что может повлиять на корректность вставки в AVL-дерево:

1. Вставка должна происходить как в стандартном двоичном дереве поиска (BST), и после вставки дерево должно быть перебалансировано, если это необходимо.
2. После каждой вставки нужно обновлять высоту и баланс каждого узла на пути от нового узла к корню дерева.
3. Необходимо провести балансировку дерева с использованием правильных вращений, если это требуется.

Функция `Insert` выглядит корректной, но давайте ее внимательно рассмотрим:

```cpp
Node* Insert(Node* root, int key) {
  if (root == nullptr) {
    Node* newNode = new Node();
    newNode->data = key;
    newNode->height = 1;
    newNode->left = nullptr;
    newNode->right = nullptr;
    newNode->balance = 0;
    return newNode;
  }

  if (key < root->data) {
    root->left = Insert(root->left, key);
  } else if (key > root->data) {
    root->right = Insert(root->right, key);
  } else { // Если ключ уже присутствует в дереве, возвращаем текущий узел
    return root;
  }

  UpdateHeightAndBalance(root);

  return BalanceTree(root);
}
```

Похоже, что функция `Insert` ведет себя верно:

1. Вставляет узел учитывая правила двоичного дерева поиска (BST).
2. Обновляет высоту и баланс после вставки.
3. Вызывает `BalanceTree`, чтобы гарантировать, что узлы на пути к корню остаются сбалансированными.

Однако, есть особенности, которые нужно учитывать:

- В `BalanceTree` вы проверяете значение `balance` на равенство `-2` или `2`, что в принципе верно для AVL-дерева, но проверяете значение `balance` дочерних узлов на равенство `-1` или `1`. Вместо этого, лучше проверить, меньше ли оно `0` (для левого поддерева) или больше `0` (для правого поддерева) для бóльшей универсальности.
- Удаление узла с копированием данных `minValueNode` может нарушить свойства AVL-дерева и его баланс. После удаления узла и копирования данных необходимо корректно перебалансировать дерево.

Если у вас возникают проблемы с вставкой, возможно, проблема может быть связана с реализацией ротаций или с балансировкой дерева после вставки. Чтобы выявить конкретную проблему, вам может потребоваться тестирование на различных наборах данных или инструментирование вашего кода с дебаг выражениями для более глубокого анализа работы функции `Insert`. На примере приведенного кода конкретные ошибки не выявлены.

#include <iostream>

struct Node {
  int data;
  int height;
  int balance;
  Node* left;
  Node* right;
};

struct AVL {
  Node* top = nullptr;

int height(Node* root) {
    if (root == nullptr)
      return 0;
    return root->height;
  }

  void UpdateHeightAndBalance(Node* node) {
  if (node == nullptr)
    return;

  node->height = 1 + std::max(height(node->left), height(node->right));
  node->balance = height(node->right) - height(node->left);
  }

  Node* newNode(int value) {
    Node* root = new Node();
    root->data = value;
    root->left = nullptr;
    root->right = nullptr;
    root->height = 1;
    return(root);
  }

  Node* RightRotation(Node* y) {
    Node* x = y->left;
    Node* T2 = x->right;

    x->right = y;
    y->left = T2;

    UpdateHeightAndBalance(y);
    UpdateHeightAndBalance(x);

    return x;
  }

  Node* LeftRotation(Node* x) {
    Node* y = x->right;
    Node* T2 = y->left;

    y->left = x;
    x->right = T2;

    UpdateHeightAndBalance(x);
    UpdateHeightAndBalance(y);

    return y;
  }

Node* BalanceTree(Node* node) {
  if (node == nullptr) return node;

  UpdateHeightAndBalance(node);

  if (node->balance == -2 && node->left->balance != -1) {
      return RightRotation(node);
  } else if (node->balance == -2 && node->left->balance == 1) {
      node->left = LeftRotation(node->left);
      return RightRotation(node);
  } else if (node->balance == 2 && node->right->balance != -1) {
      return LeftRotation(node);
  } else if (node->balance == 2 && node->right->balance == -1) {
      node->right = RightRotation(node->right);
      return LeftRotation(node);
  }

  return node;
}

  Node* Insert(Node* root, int key) {
    if (root == nullptr) {
      Node* newNode = new Node();
      newNode->data = key;
      newNode->height = 1;
      newNode->left = nullptr;
      newNode->right = nullptr;
      newNode->balance = 0;
      return newNode;
    }

  if (key < root->data) {
    root->left = Insert(root->left, key);
  } else if (key > root->data) {
    root->right = Insert(root->right, key);
  } else {
    return root;
  }

  UpdateHeightAndBalance(root);

  return BalanceTree(root);
}

Node* minValueNode(Node* node) {
    Node* current = node;
    while (current && current->left != nullptr)
        current = current->left;
    return current;
}

Node* Delete(Node* root, int key) {
  if (root == nullptr) return root;

  if (key < root->data) {
    root->left = Delete(root->left, key);
  } else if (key > root->data) {
    root->right = Delete(root->right, key);
  } else {
    if ((root->left == nullptr) || (root->right == nullptr)) {
      Node* temp = root->left ? root->left : root->right;

      if (temp == nullptr) {
        temp = root;
        root = nullptr;
      } else {
        *root = *temp;
      }
      delete temp;
    } else {
      Node* temp = minValueNode(root->right);
      root->data = temp->data;
      root->right = Delete(root->right, temp->data);
    }
  }

  if (root == nullptr) return root;

   UpdateHeightAndBalance(root);

  return BalanceTree(root);
}

  bool Exists(Node* root, int key) {
    if (root == nullptr) return false;

    if (root->data == key) {
      return true;
    }
    else if (root->data > key) {
      return Exists(root->left, key);
    }
    else {
      return Exists(root->right, key);
    }
  }
};

int main() {
  std::ios_base::sync_with_stdio(false);
  std::cin.tie(0);
  std::cout.tie(0);
  char cmd;
  AVL tree;
  int n;
  std::cin >> n;
  for (int i = 0; i < n; ++i) {
    std::cin >> cmd;
    if (cmd == 'A') {
      int x;
      std::cin >> x;
      tree.top = tree.Insert(tree.top, x);
      std::cout << (tree.top == nullptr? 0 : tree.top->balance);
      if (i < n - 1) {
        std::cout << '\n';
      }
    } else if (cmd == 'D') {
      int x;
      std::cin >> x;
      tree.top = tree.Delete(tree.top, x);
      std::cout << (tree.top == nullptr? 0 : tree.top->balance);
      if (i < n - 1) {
        std::cout << '\n';
      }
    } else if (cmd == 'C') {
      int x;
      std::cin >> x;
      tree.Exists(tree.top, x) ? std::cout << 'Y' : std::cout << 'N';
      if (i < n - 1) {
        std::cout << '\n';
      }
    }
  }
}



